// Legge i file di configurazione (prompt + categorie) dal filesystem
// e formatta i dati Excel come testo per Claude
//
// REQUISITO: NODE_FUNCTION_ALLOW_BUILTIN=fs nel docker-compose

const items = $input.all();
const fs = require('fs');

if (!items || items.length === 0) {
  throw new Error('Nessun dato ricevuto dal foglio Excel');
}

// --- LEGGI PROMPT E CATEGORIE DA FILE ---
let promptEstrazione = '';
let promptClassificazione = '';
let categorieJson = {};

try {
  promptEstrazione = fs.readFileSync('/files/prompt_estrai_movimenti.txt', 'utf-8');
} catch (e) {
  throw new Error('File prompt non trovato: /files/prompt_estrai_movimenti.txt — Copia i file .txt nella cartella local-files/');
}

try {
  promptClassificazione = fs.readFileSync('/files/prompt_classifica_spese.txt', 'utf-8');
} catch (e) {
  throw new Error('File prompt non trovato: /files/prompt_classifica_spese.txt');
}

try {
  const catRaw = fs.readFileSync('/files/categorie_spese.json', 'utf-8');
  categorieJson = JSON.parse(catRaw);
} catch (e) {
  throw new Error('File categorie non trovato o JSON invalido: /files/categorie_spese.json');
}

// Formatta le categorie come testo leggibile
const categorie = categorieJson.categorie || categorieJson;
let categorieText = '';
for (const [cat, val] of Object.entries(categorie)) {
  const subs = Array.isArray(val) ? val : (val.sottocategorie || []);
  categorieText += `\n${cat}:\n`;
  for (const sub of subs) {
    categorieText += `  - ${sub}\n`;
  }
}

// Sostituisci il placeholder {{categorie}} nel prompt di classificazione
const promptClassificazioneFinale = promptClassificazione.replace('{{categorie}}', categorieText);

// --- FORMATTA DATI EXCEL ---
const allHeaders = new Set();
for (const item of items) {
  for (const key of Object.keys(item.json)) {
    allHeaders.add(key);
  }
}
const headers = Array.from(allHeaders);

function excelDateToString(serial) {
  if (typeof serial !== 'number' || serial < 1 || serial > 73050) return String(serial);
  const epoch = new Date(1899, 11, 30);
  const date = new Date(epoch.getTime() + serial * 86400000);
  const dd = String(date.getDate()).padStart(2, '0');
  const mm = String(date.getMonth() + 1).padStart(2, '0');
  const yyyy = date.getFullYear();
  return `${dd}/${mm}/${yyyy}`;
}

let fileContent = 'RIGA | ' + headers.join(' | ') + '\n';
fileContent += '--- | ' + headers.map(() => '---').join(' | ') + '\n';

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const row = headers.map(h => {
    let val = item.json[h];
    if (val === null || val === undefined) return '';
    if (typeof val === 'number' && h.toLowerCase().match(/data|date|valuta/)) {
      return excelDateToString(val);
    }
    return String(val);
  });
  fileContent += `${i + 1} | ` + row.join(' | ') + '\n';
}

return [{
  json: {
    fileContent: fileContent,
    righe: items.length,
    colonne: headers,
    charCount: fileContent.length,
    promptEstrazione: promptEstrazione,
    promptClassificazione: promptClassificazioneFinale,
    categorieText: categorieText
  }
}];

