const response = $input.first().json;

let text = response.content[0].text;
text = text.replace(/```(?:json)?\s*\n?/gi, '').trim();

let transazioni = [];
try {
  transazioni = JSON.parse(text);
} catch (e) {
  // JSON troncato: prova a chiudere l'array
  const lastBrace = text.lastIndexOf('}');
  if (lastBrace > 0) {
    const fixed = text.substring(0, lastBrace + 1) + ']';
    transazioni = JSON.parse(fixed);
  } else {
    throw new Error('JSON non riparabile: ' + text.substring(0, 300));
  }
}

return transazioni.map((t, index) => ({
  json: {
    index: index,
    data: t.data,
    importo: t.importo,
    destinatario: t.destinatario,
    ordinante: t.ordinante,
    causale: t.causale,
    totaleTransazioni: transazioni.length
  }
}));

// Aggrega tutte le transazioni in un unico JSON array
// e prepara il payload per il nodo di classificazione Claude

const items = $input.all();

const transazioni = items.map(item => ({
  index: item.json.index,
  data: item.json.data,
  importo: item.json.importo,
  destinatario: item.json.destinatario,
  ordinante: item.json.ordinante,
  causale: item.json.causale
}));

// Recupera il prompt di classificazione dal nodo "Formatta Dati e Carica Config"
const configNode = $('Formatta Dati e Carica Config').first();
const promptClassificazione = configNode.json.promptClassificazione;

return [{
  json: {
    transazioniJson: JSON.stringify(transazioni),
    totaleTransazioni: transazioni.length,
    promptClassificazione: promptClassificazione
  }
}];

